-- 修改生成报告trigger
UPDATE `object_validations` SET `trigger_code` = 'from orionbase.common import models\nuserid = instance.owner.id\n# 报告阶段自动拷贝计划阶段成本中心\nif (instance.state.name == \'save\' and instance.record_type.name.endswith(\'__report\')):\n    if instance.id and instance.event_id:\n        if not models.CustomObjects4.objects.filter(deleted=0,event_1_id=instance.id).exists():\n            to_copy_cost = []\n            from_cost_data = models.CustomObjects4.objects.filter(deleted=0,event_1_id=instance.event_id)\n            if from_cost_data:\n                for data in from_cost_data:\n                    data.id = None\n                    data.event_1_id = instance.id\n                    to_copy_cost.append(data)\n            if to_copy_cost:\n                models.CustomObjects4.objects.bulk_create(to_copy_cost, batch_size=500)\n        if not models.CustomObjects5.objects.filter(deleted=0, event_1_id=instance.id).exists():\n            to_copy_expense = []\n            from_expense_data = models.CustomObjects5.objects.filter(deleted=0, event_1_id=instance.event_id)\n            if from_expense_data:\n                for data in from_expense_data:\n                    data.id = None\n                    data.event_1_id = instance.id\n                    to_copy_expense.append(data)\n            if to_copy_expense:\n                models.CustomObjects5.objects.bulk_create(to_copy_expense, batch_size=500)' WHERE (`id` = 'f083128a-5353-4ab0-b4ac-462307111ee0');
-- 修改拜访trigger
UPDATE `object_validations` SET `trigger_code` = 'import datetime\nfrom orionbase.common.models import Calls\nnow = datetime.datetime.now()\nnow_time = datetime.datetime.now().date()\nallow_start_date = (now - datetime.timedelta(days=2, hours=0, minutes=0, seconds=0)).date()\nallow_end_date = (now + datetime.timedelta(days=2, hours=0, minutes=0, seconds=0)).date()\npre_call_date = \'1908-01-01\'\nif instance.id:\n    calls = Calls.objects.filter(id=instance.id)\n    call = calls[0] if calls else None\n    pre_call_date = call.call_date\n    if type(pre_call_date) == datetime.date:\n        pre_call_date = pre_call_date\n    else:\n        pre_call_date = datetime.datetime.strptime(pre_call_date, \'%Y-%m-%d\').date()\npost_call_date = instance.call_date\nif type(post_call_date) == datetime.date:\n    post_call_date = post_call_date\nelse:\n    post_call_date = datetime.datetime.strptime(post_call_date, \'%Y-%m-%d\').date()\nif pre_call_date  and pre_call_date != post_call_date:\n    if post_call_date < allow_start_date:\n        message = \'仅可创建2天以内拜访\'\n        raise create_validation_trigger_rule_errors(message)\n    if post_call_date > now_time:\n        message = \'不能创建未来的拜访\'\n        raise create_validation_trigger_rule_errors(message)' WHERE (`id` = 'hxf4ef70-e980-11e9-b9aa-0298a739dec0');

-- 添加第三方费用时更新会议费用
-- INSERT INTO `object_validations` (`id`, `object_id`, `label`, `description`, `type`, `trigger_code`, `error_message`, `deleted`, `created_by`, `created_on`, `modified_by`, `modified_on`, `edit_type`, `is_active`, `source`, `name`, `version`) VALUES ('8a6d0c1a-6b05-4919-b1ee-06b8e3111960', 'd9ec50bd-7bda-4d4a-89f0-f3b59d98b121', '添加第三方费用时更新会议总费用', '添加第三方费用时更新会议总费用', 'trigger', 'from orionbase.common import models\nfrom decimal import Decimal\ntotal_expense = sum(\ninstance.event_1.eventexpenses_set.filter(deleted=0, total_expense__isnull=False).values_list(\'total_expense\',flat=True))\nif instance.event_1.id:\n    other_expense = sum(models.CustomObjects5.objects.filter(deleted=0, event_1_id=instance.event_1.id).values_list(\'number_1\',flat=True))\n    total_expense += other_expense\nexpenses = Decimal(total_expense).quantize(Decimal(\'0.00\'))\nif instance.record_type.name.endswith(\'__report\'):\n    event_budget = Decimal(instance.event_budget).quantize(Decimal(\'0.00\'))\n    if str(expenses) and str(event_budget):\n        expenses_diff = max(expenses - event_budget, 0)\n    else:\n        expenses_diff = 0\n    models.Events.advance_objects.filter(id=instance.event_1.id).update(event_expense=expenses,\n                                                                number_4=expenses_diff\n                                                                )\nelse:\n    models.Events.advance_objects.filter(id=instance.event_1.id).update(event_budget=expenses)', '', '0', '1', '2019-06-24 11:08:42', '1', '2020-08-25 13:01:39', 'post_save', '1', 'custom', 'cs_event_budget_custom', '1');
